using System;
using System.IO;
using System.Net.Http;

string FindSudokuDir()
{
    var dir = new DirectoryInfo(Directory.GetCurrentDirectory());
    while (dir != null)
    {
        // Check if we're in the Sudoku directory
        if (File.Exists(Path.Combine(dir.FullName, "Sudoku-0-Environment-Csharp.ipynb")))
            return dir.FullName;
        // Check if Sudoku is a subdirectory
        var candidate = Path.Combine(dir.FullName, "MyIA.AI.Notebooks", "Sudoku");
        if (Directory.Exists(candidate) && File.Exists(Path.Combine(candidate, "Sudoku-0-Environment-Csharp.ipynb")))
            return candidate;
        dir = dir.Parent;
    }
    return Directory.GetCurrentDirectory();
}

