        Console.WriteLine($"Telecharge: {ChocoJar} ({data.Length} bytes)");
    }
    catch (Exception ex)
    {
        Console.WriteLine($"JAR non telecharge (optionnel, non requis) : {ex.GetType().Name}");
    }
}
