// Graphique en barres groupees (rendu ASCII) : temps moyen par difficulte et solveur.
public static void PlotBenchmarkBarsAscii(Dictionary<string, Dictionary<string, BenchResult>> results)
{
    var diffs = new[] { "Easy", "Medium", "Hard", "Expert" };
    Console.WriteLine("Benchmark : temps moyen (ms) - echelle log10 (1 '#' ~= 0.2 unite log)");
    foreach (var d in diffs)
    {
        Console.WriteLine($"\n[{d}]");
        foreach (var name in results.Keys)
        {
            double t = results[name][d].TimeAvgMs;
            int bars = 1;
            if (t > 0)
            {
                double lg = Math.Log10(t + 1e-9);
                bars = (int)Math.Round(Math.Max(0, lg + 1) * 5);
                bars = Math.Min(40, Math.Max(1, bars));
            }
            Console.WriteLine($"  {name,-20} {new string('#', bars)} {t,9:F2} ms  [{results[name][d].Solved}/{results[name][d].Count}]");
        }
    }
}

PlotBenchmarkBarsAscii(results);

// Boxplots ASCII de la distribution des temps pour chaque solveur.
public static void PlotBoxplotsAscii(Dictionary<string, Dictionary<string, BenchResult>> results)
{
    var diffs = new[] { "Easy", "Medium", "Hard", "Expert" };
    foreach (var d in diffs)
    {
        Console.WriteLine($"\n=== Distribution - {d} (min | mediane | max, ms) ===");
        foreach (var name in results.Keys)
        {
            var ts = results[name][d].TimesMs;
            if (ts.Count == 0) { Console.WriteLine($"  {name,-20} (no data)"); continue; }
            var sorted = ts.OrderBy(x => x).ToList();
            double mn = sorted[0], mx = sorted[^1];
            double med = sorted[sorted.Count / 2];
            int span = (int)Math.Round(Math.Max(1, (Math.Log10(mx + 1e-9) - Math.Log10(mn + 1e-9)) * 8));
            string bar = "[" + new string('-', Math.Max(1, span / 3)) + "|"
                         + new string('-', Math.Max(1, span * 2 / 3)) + "]";
            Console.WriteLine($"  {name,-20} {bar}  {mn,8:F2} | {med,8:F2} | {mx,8:F2}");
        }
    }
}

PlotBoxplotsAscii(results);

// Solveur Norvig etendu avec forward checking explicite.
// Apres chaque assignation, on verifie que toutes les cases vides ont encore
// au moins un candidat ; si un domaine est vide, on echoue sans recurser.
public class NorvigForwardCheckingSolver : NorvigSolver
{
    public int FcCuts { get; private set; }

    public bool SolveFc(SudokuGrid grid)
    {
        CallCount = 0;
        FcCuts = 0;
        var values = ParseGrid(grid.ToFlatString());
        if (values == null) return false;
        var result = SearchFc(values);
        if (result == null) return false;
        for (int i = 0; i < 81; i++)
            grid.Cells[i / 9][i % 9] = result[Squares[i]][0] - '0';
        return true;
    }

    private bool ForwardCheck(Dictionary<string, string> values)
        => Squares.All(s => values[s].Length >= 1);

    protected override Dictionary<string, string> Search(Dictionary<string, string> values)
    {
        if (values == null) return null;
        CallCount++;
        if (Squares.All(s => values[s].Length == 1)) return values;
        string sBest = null; int bestLen = 10;
        foreach (var s in Squares)
            if (values[s].Length > 1 && values[s].Length < bestLen)
            { sBest = s; bestLen = values[s].Length; }
        foreach (var d in values[sBest])
        {
            var copy = new Dictionary<string, string>(values);
            var nv = Assign(copy, sBest, d.ToString());
            if (nv == null || !ForwardCheck(nv)) { FcCuts++; continue; }
            var res = Search(nv);
            if (res != null) return res;
        }
        return null;
    }

    // Recherche dediee (forward-checking) ; distincte de Search pour clarte.
    private Dictionary<string, string> SearchFc(Dictionary<string, string> values)
        => Search(values);
}

