import concurrent.futures

def run_benchmark(solvers, puzzle_sets, max_puzzles=3, timeout_s=30):
    """Execute chaque solveur sur chaque ensemble de puzzles et collecte les temps."""
    results = {}
    for solver_name, solver in solvers.items():
        results[solver_name] = {}
        for diff_name, puzzles in puzzle_sets.items():
            times_ms = []
            solved = 0
            count = 0
            for puzzle_str in puzzles[:max_puzzles]:
                grid = SudokuGrid.from_string(puzzle_str)
                g = grid.clone()
                count += 1
                success = False
                start = time.time()
                try:
                    with concurrent.futures.ThreadPoolExecutor(max_workers=1) as executor:
                        future = executor.submit(solver.solve, g)
                        success = future.result(timeout=timeout_s)
                except concurrent.futures.TimeoutError:
                    success = False
                except Exception:
                    success = False
                elapsed_ms = (time.time() - start) * 1000
                if success:
                    solved += 1
                times_ms.append(elapsed_ms)
            results[solver_name][diff_name] = {
                'time_avg_ms': float(np.mean(times_ms)) if times_ms else 0.0,
                'solved': solved,
                'count': count,
                'times_ms': times_ms,
                'time_total_ms': sum(times_ms),
            }
    return results

print("Fonction definie : run_benchmark")

class NorvigForwardCheckingSolver:
    """
    Solveur Norvig etendu avec forward checking explicite (Option B).

    Principe : apres chaque assignation tentative dans le backtracking,
    on verifie que toutes les cases vides ont encore au moins un candidat.
    Si une case a un domaine vide, on echoue immediatement sans recurser.

    Difference avec Norvig standard : la propagation de Norvig detecte deja
    les contradictions via _eliminate, mais le forward check explicite
    permet d'echouer avant de lancer un nouvel appel recursif (coupe precoce).
    """

    def __init__(self):
        self.call_count = 0
        self.fc_cuts = 0  # Nombre de branches coupees par le forward checking

        # Structure identique a NorvigSolver
        self.rows = 'ABCDEFGHI'
        self.cols = '123456789'
        self.squares = [r + c for r in self.rows for c in self.cols]
        self.unitlist = (
            [[r + c for c in self.cols] for r in self.rows] +
            [[r + c for r in self.rows] for c in self.cols] +
            [[r + c for r in rs for c in cs]
             for rs in ('ABC', 'DEF', 'GHI') for cs in ('123', '456', '789')]
        )
        self.units = {s: [u for u in self.unitlist if s in u] for s in self.squares}
        self.peers = {s: set(sum(self.units[s], [])) - {s} for s in self.squares}

    def solve(self, grid: SudokuGrid) -> bool:
        self.call_count = 0
        self.fc_cuts = 0
        grid_str = grid.to_string()
        values = self._parse_grid(grid_str)
        if values is False:
            return False
        result = self._search(values)
        if result is False:
            return False
        for i, s in enumerate(self.squares):
            grid.cells[i // 9][i % 9] = int(result[s])
        return True

    def _parse_grid(self, grid_str):
        values = {s: '123456789' for s in self.squares}
        for s, d in zip(self.squares, grid_str):
            if d in '123456789':
                if not self._assign(values, s, d):
                    return False
        return values

    def _assign(self, values, s, d):
        """Assigne d a s en eliminant toutes les autres valeurs."""
        other_values = values[s].replace(d, '')
        if all(self._eliminate(values, s, d2) for d2 in other_values):
            return values
        return False

    def _eliminate(self, values, s, d):
        """Elimine d des candidats de s et propage."""
        if d not in values[s]:
            return values
        values[s] = values[s].replace(d, '')
        if len(values[s]) == 0:
            return False
        if len(values[s]) == 1:
            d2 = values[s]
            if not all(self._eliminate(values, s2, d2) for s2 in self.peers[s]):
                return False
        for u in self.units[s]:
            dplaces = [s2 for s2 in u if d in values[s2]]
            if len(dplaces) == 0:
                return False
            if len(dplaces) == 1:
                if not self._assign(values, dplaces[0], d):
                    return False
        return values

    def _forward_check(self, values) -> bool:
        """Forward checking : toutes les cases doivent avoir au moins un candidat."""
        return all(len(values[s]) >= 1 for s in self.squares)

    def _search(self, values):
        """Recherche DFS avec MRV + forward checking avant recursion."""
        if values is False:
            return False
        self.call_count += 1

        if all(len(values[s]) == 1 for s in self.squares):
            return values

        # MRV : case non resolue avec le moins de candidats
        _, s = min((len(values[s]), s) for s in self.squares if len(values[s]) > 1)

        for d in values[s]:
            new_values = self._assign(values.copy(), s, d)

            # Forward checking : echec rapide si une case se retrouve sans candidat
            if new_values is False or not self._forward_check(new_values):
                self.fc_cuts += 1
                continue

            result = self._search(new_values)
            if result:
                return result
        return False


