    [[r+c for r in rows4] for c in cols4] +
    [[r+c for r in rs for c in cs] for rs in ('AB','CD') for cs in ('12','34')]
)

units4 = {s: [u for u in unitlist4 if s in u] for s in squares4}
peers4 = {s: set(sum(units4[s], [])) - {s} for s in squares4}

def assign4(values, s, d):
    other_values = values[s].replace(d, '')
    if all(eliminate4(values, s, d2) for d2 in other_values):
        return values
    else:
        return None

def eliminate4(values, s, d):
    if d not in values[s]:
        return True
    values[s] = values[s].replace(d, '')
    if len(values[s]) == 0:
        return False
    elif len(values[s]) == 1:
        d2 = values[s]
        if not all(eliminate4(values, s2, d2) for s2 in peers4[s]):
            return False
    for u in units4[s]:
        dplaces = [s2 for s2 in u if d in values[s2]]
        if len(dplaces) == 0:
            return False
        elif len(dplaces) == 1:
            if not assign4(values, dplaces[0], d):
                return False
    return True

def parse_grid4(grid):
    values = {s: digits4 for s in squares4}
    for s, d in zip(squares4, grid):
        if d in digits4 and not assign4(values, s, d):
            return None
    return values

def search4(values):
    if values is None:
        return None
    if all(len(values[s]) == 1 for s in squares4):
        return values
    n, s = min((len(values[s]), s) for s in squares4 if len(values[s]) > 1)
    for d in values[s]:
        result = search4(assign4(values.copy(), s, d))
        if result:
            return result
    return None

def solve_4x4(grid):
    return search4(parse_grid4(grid))

