HumanSudokuSolver.find_x_wings = find_x_wings
HumanSudokuSolver.apply_x_wing = apply_x_wing

print("Methodes X-Wing ajoutees.")

def solve(self, max_iterations: int = 1000) -> bool:
    """Resout le Sudoku en utilisant les strategies humaines.

    Returns:
        True si resolu, False sinon
    """
    self.strategy_counts = {}
    iteration = 0

    while not self.is_solved() and iteration < max_iterations:
        iteration += 1
        progress = False

        # 1. Naked Singles
        naked_singles = self.find_naked_singles()
        for ns in naked_singles:
            if self.apply_placement(ns, "Naked Single"):
                progress = True

        if self.is_solved():
            return True

        # 2. Hidden Singles
        hidden_singles = self.find_hidden_singles()
        for hs in hidden_singles:
            if self.apply_placement(hs, "Hidden Single"):
                progress = True

        if self.is_solved():
            return True

        # 3. Naked Pairs
        naked_pairs = self.find_naked_pairs()
        for r1, c1, r2, c2, pair_vals, unit_type in naked_pairs:
            eliminated = self.apply_naked_pair(r1, c1, r2, c2, pair_vals, unit_type)
            if eliminated > 0:
                progress = True
                self.strategy_counts["Naked Pair"] = self.strategy_counts.get("Naked Pair", 0) + 1

        # 4. Pointing Pairs
        pointing_pairs = self.find_pointing_pairs()
        for br, bc, val, direction in pointing_pairs:
            eliminated = self.apply_pointing_pair(br, bc, val, direction)
            if eliminated > 0:
                progress = True
                self.strategy_counts["Pointing Pair"] = self.strategy_counts.get("Pointing Pair", 0) + 1

        # 5. X-Wings
        x_wings = self.find_x_wings()
        for r1, r2, c1, c2, val in x_wings:
            eliminated = self.apply_x_wing(r1, r2, c1, c2, val)
            if eliminated > 0:
                progress = True
                self.strategy_counts["X-Wing"] = self.strategy_counts.get("X-Wing", 0) + 1

        if not progress:
            # Plus de progres, essayer le backtracking
            if self._backtrack():
                return True
            break

    return self.is_solved()

def _backtrack(self) -> bool:
    """Simple backtracking comme fallback."""
    # Trouver la premiere case vide
    for row in range(9):
        for col in range(9):
            if self.grid[row, col] == 0:
                candidates = list(self.candidates[row][col])

                for value in candidates:
                    if self._is_valid_placement(row, col, value):
                        self.grid[row, col] = value
                        self.placements.append(CandidateInfo(row, col, value))

                        if self._backtrack():
                            return True

                        # Annuler
                        self.grid[row, col] = 0
                        self.placements.pop()

                return False
    return True

def _is_valid_placement(self, row: int, col: int, value: int) -> bool:
    """Verifie si un placement est valide."""
    # Ligne
    if value in self.grid[row, :]:
        return False
    # Colonne
    if value in self.grid[:, col]:
        return False
    # Bloc
    br, bc = 3 * (row // 3), 3 * (col // 3)
    if value in self.grid[br:br+3, bc:bc+3]:
        return False
    return True

# Ajouter les methodes
HumanSudokuSolver.solve = solve
HumanSudokuSolver._backtrack = _backtrack
HumanSudokuSolver._is_valid_placement = _is_valid_placement

print("Methode solve ajoutee.")

class SimpleBacktracking:
    """Simple backtracking pour comparaison."""

    def __init__(self):
        self.call_count = 0

    def solve(self, puzzle_str: str) -> bool:
        grid = np.zeros((9, 9), dtype=int)
        for i in range(81):
            grid[i // 9, i % 9] = int(puzzle_str[i])

        self.call_count = 0
        return self._backtrack(grid)

    def _backtrack(self, grid: np.ndarray) -> bool:
        self.call_count += 1

        for r in range(9):
            for c in range(9):
                if grid[r, c] == 0:
                    for val in range(1, 10):
                        if self._is_valid(grid, r, c, val):
                            grid[r, c] = val
                            if self._backtrack(grid):
                                return True
                            grid[r, c] = 0
                    return False
        return True

    def _is_valid(self, grid: np.ndarray, row: int, col: int, val: int) -> bool:
        if val in grid[row, :]:
            return False
        if val in grid[:, col]:
            return False
        br, bc = 3 * (row // 3), 3 * (col // 3)
        if val in grid[br:br+3, bc:bc+3]:
            return False
        return True

print("\n=== Comparaison : Strategies Humaines vs Backtracking ===")

for i, puzzle_str in enumerate(easy_puzzles[:3]):
    print(f"\nPuzzle {i+1}:")

    # Strategies humaines
    solver = HumanSudokuSolver(puzzle_str)
    start = time.time()
    solved_h = solver.solve()
    t_h = time.time() - start

    # Backtracking
    bt = SimpleBacktracking()
    start = time.time()
    solved_bt = bt.solve(puzzle_str)
    t_bt = time.time() - start

    print(f"  Humain: {solved_h}, {t_h*1000:.2f}ms")
    print(f"  Backtracking: {solved_bt}, {t_bt*1000:.2f}ms, {bt.call_count} appels")

# Exemple resolu : Swordfish
# Generalisation du X-Wing sur 3 lignes / 3 colonnes.

def find_swordfish(self) -> list:
    """
    Trouve les Swordfish, orientation 'row' et orientation 'col'.

    Returns:
        Liste de (rows_tuple, cols_tuple, value, orientation)
    """
    results = []

    for value in range(1, 10):
        # --- Orientation LIGNES ---
        row_cols = {}
        for r in range(9):
            cols = [c for c in range(9)
                    if self.grid[r, c] == 0 and value in self.candidates[r][c]]
            if 2 <= len(cols) <= 3:
                row_cols[r] = set(cols)

        for rows in combinations(sorted(row_cols.keys()), 3):
            union_cols = row_cols[rows[0]] | row_cols[rows[1]] | row_cols[rows[2]]
            if len(union_cols) == 3:
                results.append((rows, tuple(sorted(union_cols)), value, 'row'))

        # --- Orientation COLONNES ---
        col_rows = {}
        for c in range(9):
            rows_in_c = [r for r in range(9)
                         if self.grid[r, c] == 0 and value in self.candidates[r][c]]
            if 2 <= len(rows_in_c) <= 3:
                col_rows[c] = set(rows_in_c)

        for cols in combinations(sorted(col_rows.keys()), 3):
            union_rows = col_rows[cols[0]] | col_rows[cols[1]] | col_rows[cols[2]]
            if len(union_rows) == 3:
                results.append((tuple(sorted(union_rows)), cols, value, 'col'))

    return results


def apply_swordfish(self, rows, cols, value, orientation) -> int:
    """Applique un Swordfish : elimine value des autres cases des 3 lignes/colonnes."""
    eliminated = 0
    rows_set = set(rows)
    cols_set = set(cols)

    if orientation == 'row':
        for c in cols:
            for r in range(9):
                if r not in rows_set and self.grid[r, c] == 0:
                    if value in self.candidates[r][c]:
                        self.candidates[r][c].discard(value)
                        eliminated += 1
    elif orientation == 'col':
        for r in rows:
            for c in range(9):
                if c not in cols_set and self.grid[r, c] == 0:
                    if value in self.candidates[r][c]:
                        self.candidates[r][c].discard(value)
                        eliminated += 1

    return eliminated


HumanSudokuSolver.find_swordfish = find_swordfish
HumanSudokuSolver.apply_swordfish = apply_swordfish

print("Methode definie : find_swordfish")

# Exemple resolu : XY-Wing

def _are_peers(self, r1: int, c1: int, r2: int, c2: int) -> bool:
    """Deux cases sont peers si elles partagent ligne, colonne ou bloc (et sont distinctes)."""
    if (r1, c1) == (r2, c2):
        return False
    if r1 == r2 or c1 == c2:
        return True
    if (r1 // 3 == r2 // 3) and (c1 // 3 == c2 // 3):
        return True
    return False


def find_xy_wings(self) -> list:
    """
    Trouve les XY-Wings.

    Returns:
        Liste de (pivot, wing1, wing2, z)
        - pivot, wing1, wing2 : tuples (row, col)
        - z : valeur a eliminer des cases visibles des deux ailes
    """
    results = []
    seen = set()

    # Collecter toutes les cases bi-valuees
    bivalue = [(r, c) for r in range(9) for c in range(9)
               if self.grid[r, c] == 0 and len(self.candidates[r][c]) == 2]

    for (rp, cp) in bivalue:
        pivot_cands = self.candidates[rp][cp]
        # Notations : candidats du pivot = {X, Y}
        x, y = sorted(pivot_cands)

        # Peers bi-valuees du pivot
        peers = [(r, c) for (r, c) in bivalue
                 if self._are_peers(rp, cp, r, c)]

        for (r1, c1) in peers:
            w1 = self.candidates[r1][c1]
            # Aile 1 doit partager exactement un candidat avec le pivot
            if x in w1 and y not in w1:
                z_set = w1 - {x}
            elif y in w1 and x not in w1:
                z_set = w1 - {y}
            else:
                continue  # w1 = {X,Y} (meme que pivot) ou aucun partage
            z = next(iter(z_set))

            # Si l'aile1 a partage X, on cherche aile2 = {Y, Z}
            # Si l'aile1 a partage Y, on cherche aile2 = {X, Z}
            if x in w1:
                target_w2 = {y, z}
            else:
                target_w2 = {x, z}

            for (r2, c2) in peers:
                if (r2, c2) == (r1, c1):
                    continue
                if self.candidates[r2][c2] != target_w2:
                    continue

                # Cle canonique pour eviter les doublons (ordre des ailes)
                key = (
                    (rp, cp),
                    frozenset([(r1, c1), (r2, c2)]),
                    z
                )
                if key in seen:
                    continue
                seen.add(key)

                results.append(((rp, cp), (r1, c1), (r2, c2), z))

    return results


def apply_xy_wing(self, pivot, wing1, wing2, z) -> int:
    """
    Applique un XY-Wing : elimine z des cases visibles des DEUX ailes
    (sauf pivot, wing1 et wing2 eux-memes).

    Returns:
        Nombre de candidats elimines.
    """
    eliminated = 0
    r1, c1 = wing1
    r2, c2 = wing2

    excluded = {pivot, wing1, wing2}

    for r in range(9):
        for c in range(9):
            if (r, c) in excluded:
                continue
            if self.grid[r, c] != 0:
                continue
            # Doit voir les deux ailes
            if self._are_peers(r, c, r1, c1) and self._are_peers(r, c, r2, c2):
                if z in self.candidates[r][c]:
                    self.candidates[r][c].discard(z)
                    eliminated += 1

    return eliminated


HumanSudokuSolver._are_peers = _are_peers
HumanSudokuSolver.find_xy_wings = find_xy_wings
HumanSudokuSolver.apply_xy_wing = apply_xy_wing

print("Methodes definies : _are_peers, find_xy_wings")

using System;

using System.Collections.Generic;

using System.Linq;



/// <summary>

/// Represente le graphe de contraintes d'un Sudoku.

/// 81 sommets (cellules), aretes entre cellules en conflit.

/// </summary>

public class SudokuGraph

{

    // Nombre de sommets (81 cellules)

    public const int VertexCount = 81;



    // Nombre de couleurs (valeurs 1-9)

    public const int ColorCount = 9;



    // Liste d'adjacence : adjacency[v] = liste des voisins du sommet v

    private readonly List<int>[] _adjacency;



    // Degre de chaque sommet

    private readonly int[] _degrees;



    // Grille Sudoku associee

    private readonly SudokuGrid _grid;



    // Cellules pre-coloriees (indices fixes)

    private readonly HashSet<int> _fixedVertices;



    /// <summary>

    /// Construit le graphe a partir d'une grille Sudoku.

    /// </summary>

    public SudokuGraph(SudokuGrid grid)

    {

        _grid = grid;

        _adjacency = new List<int>[VertexCount];

        _degrees = new int[VertexCount];

        _fixedVertices = new HashSet<int>();



        // Initialiser les listes d'adjacence

        for (int i = 0; i < VertexCount; i++)

        {

            _adjacency[i] = new List<int>();

        }



        // Construire les aretes a partir des contraintes Sudoku

        BuildEdges();



        // Identifier les cellules pre-coloriees

        IdentifyFixedVertices();

    }



    /// <summary>

    /// Construit les aretes du graphe.

    /// Chaque cellule est reliee a ses voisins de ligne, colonne et bloc.

    /// </summary>

    private void BuildEdges()

    {

        for (int row = 0; row < 9; row++)

        {

            for (int col = 0; col < 9; col++)

            {

                int vertex = ToVertexIndex(row, col);

                var neighbors = GetNeighborVertices(row, col);



                foreach (var neighbor in neighbors)

                {

                    if (!_adjacency[vertex].Contains(neighbor))

                    {

                        _adjacency[vertex].Add(neighbor);

                        _degrees[vertex]++;

                    }

                }

            }

        }

    }



    /// <summary>

    /// Obtient tous les sommets voisins d'une cellule.

    /// </summary>

    private HashSet<int> GetNeighborVertices(int row, int col)

    {

        var neighbors = new HashSet<int>();



        // Voisins de ligne

        for (int c = 0; c < 9; c++)

            if (c != col)

                neighbors.Add(ToVertexIndex(row, c));



        // Voisins de colonne

        for (int r = 0; r < 9; r++)

            if (r != row)

                neighbors.Add(ToVertexIndex(r, col));



        // Voisins de bloc 3x3

        int blockRow = (row / 3) * 3;

        int blockCol = (col / 3) * 3;

        for (int r = blockRow; r < blockRow + 3; r++)

        {

            for (int c = blockCol; c < blockCol + 3; c++)

            {

                if (r != row || c != col)

                    neighbors.Add(ToVertexIndex(r, c));

            }

        }



        return neighbors;

    }



    /// <summary>

    /// Identifie les cellules pre-coloriees (valeurs fixees).

    /// </summary>

    private void IdentifyFixedVertices()

    {

        for (int row = 0; row < 9; row++)

        {

            for (int col = 0; col < 9; col++)

            {

                if (_grid.Cells[row, col] > 0)

                {

                    _fixedVertices.Add(ToVertexIndex(row, col));

                }

            }

        }

    }



    // Conversion coordonnees <-> index de sommet

    public static int ToVertexIndex(int row, int col) => row * 9 + col;

    public static (int row, int col) ToCoordinates(int vertex) => (vertex / 9, vertex % 9);



    // Acces aux proprietes du graphe

    public IReadOnlyList<int> GetNeighbors(int vertex) => _adjacency[vertex];

    public int GetDegree(int vertex) => _degrees[vertex];

    public bool IsFixed(int vertex) => _fixedVertices.Contains(vertex);

    public int GetInitialColor(int vertex)

    {

        var (row, col) = ToCoordinates(vertex);

        return _grid.Cells[row, col];

    }



    /// <summary>

    /// Obtient les couleurs disponibles pour un sommet.

    /// </summary>

    public HashSet<int> GetAvailableColors(int vertex, int[] coloring)

    {

        var usedColors = new HashSet<int>();



        foreach (var neighbor in _adjacency[vertex])

        {

            if (coloring[neighbor] > 0)

                usedColors.Add(coloring[neighbor]);

        }



        var available = new HashSet<int>();

        for (int color = 1; color <= ColorCount; color++)

        {

            if (!usedColors.Contains(color))

                available.Add(color);

        }



        return available;

    }



    /// <summary>

    /// Verifie si une coloration est valide.

    /// </summary>

    public bool IsValidColoring(int[] coloring)

    {

        for (int v = 0; v < VertexCount; v++)

        {

            if (coloring[v] == 0) continue;



            foreach (var neighbor in _adjacency[v])

            {

                if (coloring[neighbor] == coloring[v])

                    return false;

            }

        }

        return true;

    }



    /// <summary>

    /// Affiche les statistiques du graphe.

    /// </summary>

    public void PrintStatistics()

    {

        int totalEdges = _degrees.Sum() / 2;

        int maxDegree = _degrees.Max();

        int minDegree = _degrees.Min();



        Console.WriteLine("=== Statistiques du Graphe Sudoku ===");

        Console.WriteLine($"Sommets: {VertexCount}");

        Console.WriteLine($"Aretes: {totalEdges}");

        Console.WriteLine($"Degre min: {minDegree}, max: {maxDegree}");

        Console.WriteLine($"Cellules fixees: {_fixedVertices.Count}");

        Console.WriteLine($"Cellules a colorier: {VertexCount - _fixedVertices.Count}");

    }

}

Console.WriteLine("Classe SudokuGraph definie (graphe de contraintes 81 sommets)");

/// <summary>

/// Solveur par coloration de graphe avec backtracking simple.

/// </summary>

public class GraphColoringBacktracking : ISudokuSolver

{

    private int _nodesExplored;

    private int _backtracks;



    public int NodesExplored => _nodesExplored;

    public int Backtracks => _backtracks;



    public SudokuGrid Solve(SudokuGrid grid)

    {

        _nodesExplored = 0;

        _backtracks = 0;



        var graph = new SudokuGraph(grid);

        var coloring = new int[SudokuGraph.VertexCount];



        // Initialiser avec les valeurs pre-existantes

        for (int v = 0; v < SudokuGraph.VertexCount; v++)

        {

            coloring[v] = graph.GetInitialColor(v);

        }



        // Lancer le backtracking

        if (BacktrackColor(graph, coloring, 0))

        {

            return ColoringToGrid(coloring, grid);

        }



        return grid; // Echec

    }



    /// <summary>

    /// Backtracking recursif pour la coloration.

    /// </summary>

    private bool BacktrackColor(SudokuGraph graph, int[] coloring, int vertex)

    {

        _nodesExplored++;



        // Trouver le prochain sommet a colorier

        while (vertex < SudokuGraph.VertexCount)

        {

            if (coloring[vertex] == 0) break; // Sommet non colorie

            vertex++;

        }



        // Tous les sommets sont colories

        if (vertex >= SudokuGraph.VertexCount)

            return true;



        // Obtenir les couleurs disponibles

        var availableColors = graph.GetAvailableColors(vertex, coloring);



        // Essayer chaque couleur

        foreach (var color in availableColors)

        {

            coloring[vertex] = color;



            if (BacktrackColor(graph, coloring, vertex + 1))

                return true;



            // Backtrack

            coloring[vertex] = 0;

            _backtracks++;

        }



        return false; // Aucune couleur possible

    }



    /// <summary>

    /// Convertit une coloration en grille Sudoku.

    /// </summary>

    private SudokuGrid ColoringToGrid(int[] coloring, SudokuGrid original)

    {

        var result = (SudokuGrid)original.Clone();

        for (int v = 0; v < SudokuGraph.VertexCount; v++)

        {

            var (row, col) = SudokuGraph.ToCoordinates(v);

            result.Cells[row, col] = coloring[v];

        }

        return result;

    }

}

Console.WriteLine("Classe GraphColoringBacktracking definie (coloration par backtracking)");

// Test avec un Sudoku facile
