Console.WriteLine($"Sudoku original:\n{easySudoku}");

var solver = new GraphColoringBacktracking();
var stopwatch = System.Diagnostics.Stopwatch.StartNew();
var solved = solver.Solve(easySudoku);
stopwatch.Stop();

